import 'package:flutter/material.dart';\nimport 'package:intl/intl.dart';\nimport '../../../core/theme/app_theme.dart';\nimport '../../../core/constants/app_colors.dart';\nimport '../../../data/models/ticket_model.dart';\n\nclass TicketTimeline extends StatelessWidget {\n  final List<TicketHistory> history;\n\n  const TicketTimeline({\n    super.key,\n    required this.history,\n  });\n\n  @override\n  Widget build(BuildContext context) {\n    if (history.isEmpty) {\n      return Container(\n        padding: const EdgeInsets.all(AppTheme.lg),\n        child: Column(\n          children: [\n            Container(\n              width: 80,\n              height: 80,\n              decoration: BoxDecoration(\n                color: AppColors.infoLight,\n                borderRadius: BorderRadius.circular(AppTheme.radiusLarge),\n              ),\n              child: const Icon(\n                Icons.history_outlined,\n                size: 40,\n                color: AppColors.info,\n              ),\n            ),\n            const SizedBox(height: AppTheme.md),\n            Text(\n              'No Activity Yet',\n              style: AppTheme.headline3.copyWith(\n                color: AppColors.textPrimary,\n                fontWeight: FontWeight.w600,\n              ),\n            ),\n            const SizedBox(height: AppTheme.sm),\n            Text(\n              'Ticket activity will appear here',\n              style: AppTheme.bodyMedium.copyWith(\n                color: AppColors.textSecondary,\n              ),\n              textAlign: TextAlign.center,\n            ),\n          ],\n        ),\n      );\n    }\n\n    return Container(\n      padding: const EdgeInsets.all(AppTheme.md),\n      child: Column(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          Text(\n            'Ticket Activity',\n            style: AppTheme.headline3.copyWith(\n              color: AppColors.textPrimary,\n              fontWeight: FontWeight.w600,\n            ),\n          ),\n          const SizedBox(height: AppTheme.md),\n          ListView.builder(\n            shrinkWrap: true,\n            physics: const NeverScrollableScrollPhysics(),\n            itemCount: history.length,\n            itemBuilder: (context, index) {\n              final historyItem = history[index];\n              final isLast = index == history.length - 1;\n              \n              return TimelineItem(\n                history: historyItem,\n                isLast: isLast,\n              );\n            },\n          ),\n        ],\n      ),\n    );\n  }\n}\n\nclass TimelineItem extends StatelessWidget {\n  final TicketHistory history;\n  final bool isLast;\n\n  const TimelineItem({\n    super.key,\n    required this.history,\n    required this.isLast,\n  });\n\n  @override\n  Widget build(BuildContext context) {\n    return Row(\n      crossAxisAlignment: CrossAxisAlignment.start,\n      children: [\n        // Timeline dots and line\n        Column(\n          children: [\n            Container(\n              width: 40,\n              height: 40,\n              decoration: BoxDecoration(\n                color: _getActionColor().withOpacity(0.1),\n                borderRadius: BorderRadius.circular(AppTheme.radiusLarge),\n                border: Border.all(\n                  color: _getActionColor(),\n                  width: 2,\n                ),\n              ),\n              child: Icon(\n                _getActionIcon(),\n                size: 20,\n                color: _getActionColor(),\n              ),\n            ),\n            if (!isLast)\n              Container(\n                width: 2,\n                height: 60,\n                color: AppColors.border,\n              ),\n          ],\n        ),\n        const SizedBox(width: AppTheme.md),\n        // Content\n        Expanded(\n          child: Container(\n            margin: const EdgeInsets.only(bottom: AppTheme.md),\n            padding: const EdgeInsets.all(AppTheme.md),\n            decoration: BoxDecoration(\n              color: AppColors.surface,\n              borderRadius: BorderRadius.circular(AppTheme.radiusSmall),\n              boxShadow: AppTheme.cardShadow,\n            ),\n            child: Column(\n              crossAxisAlignment: CrossAxisAlignment.start,\n              children: [\n                Row(\n                  children: [\n                    Container(\n                      padding: const EdgeInsets.symmetric(\n                        horizontal: AppTheme.sm,\n                        vertical: AppTheme.xs,\n                      ),\n                      decoration: BoxDecoration(\n                        color: _getActionColor().withOpacity(0.1),\n                        borderRadius: BorderRadius.circular(AppTheme.radiusSmall),\n                      ),\n                      child: Text(\n                        _getActionDisplay(),\n                        style: AppTheme.bodySmall.copyWith(\n                          color: _getActionColor(),\n                          fontWeight: FontWeight.w600,\n                        ),\n                      ),\n                    ),\n                    const SizedBox(width: AppTheme.sm),\n                    Text(\n                      'by ${history.actorName}',\n                      style: AppTheme.bodySmall.copyWith(\n                        color: AppColors.textSecondary,\n                      ),\n                    ),\n                  ],\n                ),\n                const SizedBox(height: AppTheme.sm),\n                Text(\n                  history.description,\n                  style: AppTheme.bodyMedium.copyWith(\n                    color: AppColors.textPrimary,\n                  ),\n                ),\n                if (history.previousStatus != null && history.newStatus != null) ..[\n                  const SizedBox(height: AppTheme.sm),\n                  Row(\n                    children: [\n                      Text(\n                        'Status changed:',\n                        style: AppTheme.bodySmall.copyWith(\n                          color: AppColors.textSecondary,\n                        ),\n                      ),\n                      const SizedBox(width: AppTheme.xs),\n                      Container(\n                        padding: const EdgeInsets.symmetric(\n                          horizontal: AppTheme.sm,\n                          vertical: AppTheme.xs,\n                        ),\n                        decoration: BoxDecoration(\n                          color: _getStatusColor(history.previousStatus!).withOpacity(0.1),\n                          borderRadius: BorderRadius.circular(AppTheme.radiusSmall),\n                        ),\n                        child: Text(\n                          history.previousStatus!.toUpperCase(),\n                          style: AppTheme.bodySmall.copyWith(\n                            color: _getStatusColor(history.previousStatus!),\n                            fontWeight: FontWeight.w600,\n                          ),\n                        ),\n                      ),\n                      const Icon(Icons.arrow_forward, size: 16, color: AppColors.textSecondary),\n                      const SizedBox(width: AppTheme.xs),\n                      Container(\n                        padding: const EdgeInsets.symmetric(\n                          horizontal: AppTheme.sm,\n                          vertical: AppTheme.xs,\n                        ),\n                        decoration: BoxDecoration(\n                          color: _getStatusColor(history.newStatus!).withOpacity(0.1),\n                          borderRadius: BorderRadius.circular(AppTheme.radiusSmall),\n                        ),\n                        child: Text(\n                          history.newStatus!.toUpperCase(),\n                          style: AppTheme.bodySmall.copyWith(\n                            color: _getStatusColor(history.newStatus!),\n                            fontWeight: FontWeight.w600,\n                          ),\n                        ),\n                      ),\n                    ],\n                  ),\n                ],\n                const SizedBox(height: AppTheme.sm),\n                Row(\n                  children: [\n                    Icon(\n                      Icons.access_time,\n                      size: 16,\n                      color: AppColors.textTertiary,\n                    ),\n                    const SizedBox(width: AppTheme.xs),\n                    Text(\n                      _formatTimestamp(history.timestamp),\n                      style: AppTheme.caption.copyWith(\n                        color: AppColors.textTertiary,\n                      ),\n                    ),\n                  ],\n                ),\n              ],\n            ),\n          ),\n        ),\n      ],\n    );\n  }\n\n  IconData _getActionIcon() {\n    switch (history.action) {\n      case 'created':\n        return Icons.add_circle_outline;\n      case 'assigned':\n        return Icons.person_add_outlined;\n      case 'reassigned':\n        return Icons.swap_horiz;\n      case 'status_changed':\n        return Icons.sync;\n      case 'message_sent':\n        return Icons.chat_outlined;\n      case 'reply_added':\n        return Icons.reply;\n      case 'resolved':\n        return Icons.check_circle_outline;\n      case 'closed':\n        return Icons.close;\n      default:\n        return Icons.info_outline;\n    }\n  }\n\n  Color _getActionColor() {\n    switch (history.action) {\n      case 'created':\n        return AppColors.primary;\n      case 'assigned':\n      case 'reassigned':\n        return AppColors.adminRole;\n      case 'status_changed':\n        return AppColors.warning;\n      case 'message_sent':\n        return AppColors.info;\n      case 'reply_added':\n        return AppColors.success;\n      case 'resolved':\n        return AppColors.success;\n      case 'closed':\n        return AppColors.gray500;\n      default:\n        return AppColors.gray500;\n    }\n  }\n\n  String _getActionDisplay() {\n    switch (history.action) {\n      case 'created':\n        return 'Created';\n      case 'assigned':\n        return 'Assigned';\n      case 'reassigned':\n        return 'Reassigned';\n      case 'status_changed':\n        return 'Status Changed';\n      case 'message_sent':\n        return 'Message Sent';\n      case 'reply_added':\n        return 'Reply Added';\n      case 'resolved':\n        return 'Resolved';\n      case 'closed':\n        return 'Closed';\n      default:\n        return history.action;\n    }\n  }\n\n  Color _getStatusColor(String status) {\n    switch (status) {\n      case 'pending':\n        return AppColors.warning;\n      case 'assigned':\n        return AppColors.adminRole;\n      case 'in_progress':\n        return AppColors.info;\n      case 'resolved':\n        return AppColors.success;\n      case 'closed':\n        return AppColors.gray500;\n      default:\n        return AppColors.gray500;\n    }\n  }\n\n  String _formatTimestamp(DateTime timestamp) {\n    final now = DateTime.now();\n    final difference = now.difference(timestamp);\n\n    if (difference.inDays > 0) {\n      return '${difference.inDays} day${difference.inDays == 1 ? '' : 's'} ago';\n    } else if (difference.inHours > 0) {\n      return '${difference.inHours} hour${difference.inHours == 1 ? '' : 's'} ago';\n    } else if (difference.inMinutes > 0) {\n      return '${difference.inMinutes} min${difference.inMinutes == 1 ? '' : 's'} ago';\n    } else {\n      return 'Just now';\n    }\n  }\n}
